                signature.append('I');
            } else {
                signature.append('D');
            }
        }
        return signature.toString();
    }

    // Function to find the maximum weighted matching
    public static int findMaxWeightedMatching(int T, int M) {
        int maxWeight = 0;
        for (int t = 0; t < T; t++) {
            Scanner scanner = new Scanner(System.in);
            int N = scanner.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = i + 1;
            }
            do {
                int invCount = inversionCount(arr);
                String signature = calculateSignature(arr);
                int weight = (invCount * invCount) % M;
                maxWeight = (maxWeight + weight) % M;
            } while (nextPermutation(arr));
        }
        return maxWeight;
    }

    // Function to generate the next permutation
    public static boolean nextPermutation(int[] arr) {
        int i = arr.length - 2;
        while (i >= 0 && arr[i] >= arr[i + 1]) {
            i--;
        }
        if (i < 0) {
            return false;
        }
        int j = arr.length - 1;
        while (arr[j] <= arr[i]) {
            j--;
        }
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
        int left = i + 1;
        int right = arr.length - 1;
        while (left < right) {
            temp = arr[left];
            arr[left] = arr[right];
            arr[right] = temp;
            left++;
            right--;
        }
        return true;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        int M = scanner.nextInt();
        int maxWeight = findMaxWeightedMatching(T, M);
        System.out.println(maxWeight);
    }
